#include <bits/stdc++.h>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;
    vector<int> p(n + 1);
    for (int i = 1; i <= n; ++i) {
        cin >> p[i];
    }

    // The management structure is a forest (collection of trees).
    // We need the minimum number of groups such that in each group,
    // no one is an ancestor of another. This is exactly the problem
    // of coloring the tree such that no ancestor and descendant share
    // the same color, minimizing the number of colors.
    // For each tree, the answer is its depth (longest chain length).
    // The overall answer is the maximum depth among all trees.

    vector<int> depth(n + 1, 0);
    int answer = 0;

    for (int i = 1; i <= n; ++i) {
        // Follow the chain up until we find someone with known depth or root.
        int cur = i;
        int steps = 0;
        while (cur != -1 && depth[cur] == 0) {
            cur = p[cur];
            steps++;
        }
        // Now cur has known depth (or cur == -1 which has depth 0).
        int base_depth = (cur == -1 ? 0 : depth[cur]);
        // Now we go back down and assign depths.
        // Actually easier: we can just compute the chain length by traversing again.
        // But simpler: we traverse from i up to root, counting.
        int len = 0;
        int v = i;
        while (v != -1) {
            v = p[v];
            len++;
        }
        answer = max(answer, len);
    }

    cout << answer << "\n";
    return 0;
}
